// ==============================================================
// WF1 - Extrair dados do item do monday, gerar UUID e lista de dias
// ==============================================================

// Troque pelo domínio real do app quando estiver publicado.
const APP_BASE_URL = 'http://localhost:5173';

// IDs técnicos das colunas do board "Plano Intermitentes"
const COL_CONTRATO   = 'color_mktcnxwn';
const COL_DATA_INI   = 'date_mktayxhb';
const COL_DATA_FIM   = 'date_mktasnwq';
const COL_NOME       = 'dropdown_mktadatt';

// O node "Get an item" retorna o item direto como o primeiro input.
// A depender da versão, ele pode estar embrulhado em .data ou .item.
const raw = $input.first().json;
const item = raw.data?.item ?? raw.item ?? raw;

const columnValues = item.column_values ?? [];
const getCol = (id) => columnValues.find(c => c.id === id);

const contrato   = getCol(COL_CONTRATO)?.text || null;
const dataInicio = getCol(COL_DATA_INI)?.text || null;
const dataFim    = getCol(COL_DATA_FIM)?.text || null;
const nomeCol    = getCol(COL_NOME);
const nome       = nomeCol?.text || item.name || 'Sem nome';

if (!dataInicio || !dataFim) {
  throw new Error(`Item ${item.id} sem data_inicio (${dataInicio}) ou data_fim (${dataFim}). Cheque as colunas ${COL_DATA_INI} e ${COL_DATA_FIM}.`);
}

// Gerar UUID criptográfico (disponível em Node >= 14.17)
const uuid = crypto.randomUUID();

// Montar lista de dias (inclusive início e fim)
const dias = [];
const atual = new Date(dataInicio + 'T00:00:00Z');
const fim = new Date(dataFim + 'T00:00:00Z');
while (atual <= fim) {
  dias.push(atual.toISOString().slice(0, 10));
  atual.setUTCDate(atual.getUTCDate() + 1);
}

const link = `${APP_BASE_URL}/preencher/${uuid}`;

return [{
  json: {
    uuid,
    monday_item_id: String(item.id),
    nome,
    contrato,
    data_inicio: dataInicio,
    data_fim: dataFim,
    dias,
    link,
    link_text: 'Abrir formulário'
  }
}];
